     5→//! JJK Tally command - add a new Tack to a Pace
     6→//!
     7→//! Handles pace state transitions (rough → bridled → complete/abandoned)
     8→//! and plan refinement through tack prepending.
     9→
    10→use std::path::PathBuf;
    11→
    12→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState, jjrg_read_stdin_optional as read_stdin_optional};
    14→use crate::jjrn_notch::{jjrn_format_heat_message as format_heat_message, jjrn_HeatAction as HeatAction};
    15→
    16→/// Arguments for jjx_tally command
    17→#[derive(clap::Args, Debug)]
    18→pub struct jjrtl_TallyArgs {
    19→    /// Path to the Gallops JSON file
    20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    21→    pub file: PathBuf,
    22→
    23→    /// Target Pace identity (Coronet)
    24→    pub coronet: String,
    25→
    26→    /// Target state (rough, bridled, complete, abandoned)
    27→    #[arg(long)]
    28→    pub state: Option<String>,
    29→
    30→    /// Execution guidance (required if state is bridled)
    31→    #[arg(long, short = 'd')]
    32→    pub direction: Option<String>,
    33→
    34→    /// Kebab-case display name (if provided, new Tack uses this value; otherwise inherits)
    35→    #[arg(long, short = 's')]
    36→    pub silks: Option<String>,
    37→}
    38→
    39→/// Run the tally command
    40→///
    41→/// Adds a new Tack to a Pace with optional state transition and refinement.
    42→/// If state transitions to bridled, creates an additional B commit.
    43→pub fn jjrtl_run_tally(args: jjrtl_TallyArgs) -> i32 {
    44→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
    45→
    46→    // Acquire lock FIRST - fail fast if another operation is in progress
    47→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
    48→        Ok(l) => l,
    49→        Err(e) => {
    50→            eprintln!("jjx_tally: error: {}", e);
    51→            return 1;
    52→        }
    53→    };
    54→
    55→    let text = match read_stdin_optional() {
    56→        Ok(t) => t,
    57→        Err(e) => {
    58→            eprintln!("jjx_tally: error: {}", e);
    59→            return 1;
    60→        }
    61→    };
    62→
    63→    let state = match &args.state {
    64→        Some(s) => match s.to_lowercase().as_str() {
    65→            "rough" => Some(PaceState::Rough),
    66→            "bridled" => Some(PaceState::Bridled),
    67→            "complete" => Some(PaceState::Complete),
    68→            "abandoned" => Some(PaceState::Abandoned),
    69→            _ => {
    70→                eprintln!("jjx_tally: error: invalid state '{}', must be rough, bridled, complete, or abandoned", s);
    71→                return 1;
    72→            }
    73→        },
    74→        None => None,
    75→    };
    76→
    77→    let mut gallops = match Gallops::jjrg_load(&args.file) {
    78→        Ok(g) => g,
    79→        Err(e) => {
    80→            eprintln!("jjx_tally: error loading Gallops: {}", e);
    81→            return 1;
    82→        }
    83→    };
    84→
    85→    // Get firemark and silks for commit message before we move args
    86→    let coronet_str = args.coronet.clone();
    87→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
    88→        Ok(c) => {
    89→            let parent_fm = c.jjrf_parent_firemark();
    90→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
    91→                .and_then(|h| h.paces.get(&c.jjrf_display()))
    92→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
    93→                .unwrap_or_else(|| coronet_str.clone());
    94→            (parent_fm, silks)
    95→        }
    96→        Err(e) => {
    97→            eprintln!("jjx_tally: error: {}", e);
    98→            return 1;
    99→        }
   100→    };
   101→
   102→    // Capture whether we're bridling before state is moved
   103→    let is_bridling = matches!(state, Some(PaceState::Bridled));
   104→
   105→    let tally_args = LibTallyArgs {
   106→        coronet: args.coronet,
   107→        state,
   108→        direction: args.direction,
   109→        text,
   110→        silks: args.silks,
   111→    };
   112→
   113→    match gallops.jjrg_tally(tally_args) {
   114→        Ok(()) => {
   115→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
   116→
   117→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
   118→                Ok(hash) => {
   119→                    println!("committed {}", hash);
   120→                }
   121→                Err(e) => {
   122→                    eprintln!("jjx_tally: error: {}", e);
   123→                    return 1;
   124→                }
   125→            }
   126→
   127→            // If state transitioned to bridled, create B commit
   128→            if is_bridling {
   129→                // Parse coronet to get the full identity
   130→                let coronet = match Coronet::jjrf_parse(&coronet_str) {
   131→                    Ok(c) => c,
   132→                    Err(e) => {
   133→                        eprintln!("jjx_tally: error parsing coronet for B commit: {}", e);
   134→                        return 1;
   135→                    }
   136→                };
   137→
   138→                // Get direction from the new tack
   139→                let direction_text = match gallops.heats.get(&fm.jjrf_display())
   140→                    .and_then(|h| h.paces.get(&coronet.jjrf_display()))
   141→                    .and_then(|p| p.tacks.first())
   142→                    .and_then(|t| t.direction.as_ref()) {
   143→                    Some(d) => d.clone(),
   144→                    None => {
   145→                        String::new()
   146→                    }
   147→                };
   148→
   149→                let agent = "tally"; // Agent that bridled the pace
   150→
   151→                // Build B commit message
   152→                use crate::jjrn_notch::jjrn_format_bridle_message;
   153→                let b_subject = jjrn_format_bridle_message(&coronet, agent, &silks);
   154→                let b_message = format!("{}\n\n{}", b_subject, direction_text);
   155→
   156→                // Create empty B commit using git directly (like chalk markers)
   157→                use std::process::Command;
   158→                let output = Command::new("git")
   159→                    .args(["commit", "--allow-empty", "-m", &b_message])
   160→                    .output();
   161→
   162→                match output {
   163→                    Ok(result) if result.status.success() => {
   164→                        // Get commit hash
   165→                        let hash_output = Command::new("git")
   166→                            .args(["rev-parse", "HEAD"])
   167→                            .output();
   168→
   169→                        if let Ok(hash_result) = hash_output {
   170→                            if hash_result.status.success() {
   171→                                let hash = String::from_utf8_lossy(&hash_result.stdout).trim().to_string();
   172→                                println!("B commit {}", &hash[..8.min(hash.len())]);
   173→                            }
   174→                        }
   175→                    }
   176→                    Ok(result) => {
   177→                        let stderr = String::from_utf8_lossy(&result.stderr);
   178→                        eprintln!("jjx_tally: error creating B commit: {}", stderr);
   179→                        return 1;
   180→                    }
   181→                    Err(e) => {
   182→                        eprintln!("jjx_tally: error creating B commit: {}", e);
   183→                        return 1;
   184→                    }
   185→                }
   186→            }
   187→
   188→            0
   189→        }
   190→        Err(e) => {
   191→            eprintln!("jjx_tally: error: {}", e);
   192→            1
   193→        }
   194→    }
   195→    // lock released here
   196→}
   197→

