     5→//! Parade command - Display comprehensive Heat status for project review
     6→//!
     7→//! Implements both heat view (Firemark) and pace view (Coronet).
     8→
     9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat, zjjrq_files_for_commit, zjjrq_bare_filename, zjjrq_is_infra_file};
    14→use crate::jjrs_steeplechase::{jjrs_ReinArgs, jjrs_get_entries, jjrs_SteeplechaseEntry};
    15→use std::collections::BTreeMap;
    16→use std::fs;
    17→
    18→/// Arguments for jjx_parade command
    19→#[derive(clap::Args, Debug)]
    20→pub struct jjrpd_ParadeArgs {
    21→    /// Path to the Gallops JSON file
    22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    23→    pub file: std::path::PathBuf,
    24→
    25→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
    26→    pub target: Option<String>,
    27→
    28→    /// Show paddock and full specs (heat mode only)
    29→    #[arg(long)]
    30→    pub full: bool,
    31→
    32→    /// Show only remaining paces (exclude complete/abandoned)
    33→    #[arg(long)]
    34→    pub remaining: bool,
    35→}
    36→
    37→/// Run the parade command - display comprehensive Heat status
    38→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
    39→    let gallops = match Gallops::jjrg_load(&args.file) {
    40→        Ok(g) => g,
    41→        Err(e) => {
    42→            eprintln!("jjx_parade: error: {}", e);
    43→            return 1;
    44→        }
    45→    };
    46→
    47→    // Resolve target: use provided value or auto-select first racing heat
    48→    let target = match args.target {
    49→        Some(t) => t,
    50→        None => {
    51→            // Load gallops to resolve default heat
    52→            match zjjrpd_resolve_default_heat(&gallops) {
    53→                Ok(fm) => fm,
    54→                Err(e) => {
    55→                    eprintln!("jjx_parade: error: {}", e);
    56→                    return 1;
    57→                }
    58→            }
    59→        }
    60→    };
    61→
    62→    // Determine target type by length
    63→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
    64→
    65→    if target_str.len() == 5 {
    66→        // Coronet - pace view
    67→        let coronet = match Coronet::jjrf_parse(&target) {
    68→            Ok(c) => c,
    69→            Err(e) => {
    70→                eprintln!("jjx_parade: error: {}", e);
    71→                return 1;
    72→            }
    73→        };
    74→
    75→        // Extract parent firemark
    76→        let firemark = coronet.jjrf_parent_firemark();
    77→        let heat_key = firemark.jjrf_display();
    78→        let heat = match gallops.heats.get(&heat_key) {
    79→            Some(h) => h,
    80→            None => {
    81→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
    82→                return 1;
    83→            }
    84→        };
    85→
    86→        // Find pace
    87→        let coronet_key = coronet.jjrf_display();
    88→        let pace = match heat.paces.get(&coronet_key) {
    89→            Some(p) => p,
    90→            None => {
    91→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
    92→                return 1;
    93→            }
    94→        };
    95→
    96→        // Display tack history - iterate in reverse order (oldest first)
    97→        if !pace.tacks.is_empty() {
    98→            // Print header with current state from tacks[0]
    99→            let current_tack = &pace.tacks[0];
   100→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   101→            println!("Heat: {}", heat_key);
   102→
   103→            // Show work files touched by this pace's commits
   104→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
   105→                Ok(files) if !files.is_empty() => {
   106→                    println!("Work files: {}", files.join(", "));
   107→                }
   108→                _ => {}
   109→            }
   110→            println!();
   111→
   112→            // Iterate tacks in reverse order (oldest first)
   113→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   114→                let state_str = zjjrpd_pace_state_str(&tack.state);
   115→                let basis_str = if tack.basis == "0000000" {
   116→                    "(no basis)".to_string()
   117→                } else {
   118→                    tack.basis.clone()
   119→                };
   120→
   121→                println!("[{}] {} (basis: {})", index, state_str, basis_str);
   122→                println!("    Silks: {}", tack.silks);
   123→                if let Some(ref direction) = tack.direction {
   124→                    println!("    Direction: {}", direction);
   125→                }
   126→                println!();
   127→                // Indent spec text
   128→                for line in tack.text.lines() {
   129→                    println!("    {}", line);
   130→                }
   131→                println!();
   132→            }
   133→
   134→            // Append files-per-commit bitmap
   135→            zjjrpd_print_pace_commits(&firemark, &coronet_key);
   136→        }
   137→    } else if target_str.len() == 2 {
   138→        // Firemark - heat view
   139→        let firemark = match Firemark::jjrf_parse(&target) {
   140→            Ok(fm) => fm,
   141→            Err(e) => {
   142→                eprintln!("jjx_parade: error: {}", e);
   143→                return 1;
   144→            }
   145→        };
   146→
   147→        let heat_key = firemark.jjrf_display();
   148→        let heat = match gallops.heats.get(&heat_key) {
   149→            Some(h) => h,
   150→            None => {
   151→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   152→                return 1;
   153→            }
   154→        };
   155→
   156→        if args.full {
   157→            // Full view: paddock + all specs
   158→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   159→                Ok(content) => content,
   160→                Err(e) => {
   161→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   162→                    return 1;
   163→                }
   164→            };
   165→
   166→            let status_str = match heat.status {
   167→                HeatStatus::Racing => "racing",
   168→                HeatStatus::Stabled => "stabled",
   169→                HeatStatus::Retired => "retired",
   170→            };
   171→
   172→            println!("Heat: {} ({})", heat.silks, heat_key);
   173→            println!("Status: {}", status_str);
   174→            println!("Created: {}", heat.creation_time);
   175→            println!();
   176→            println!("## Paddock");
   177→            println!();
   178→            println!("{}", paddock_content);
   179→            println!();
   180→            println!("## Paces");
   181→            println!();
   182→
   183→            for coronet_key in &heat.order {
   184→                if let Some(pace) = heat.paces.get(coronet_key) {
   185→                    if let Some(tack) = pace.tacks.first() {
   186→                        // Skip complete/abandoned if --remaining
   187→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   188→                            continue;
   189→                        }
   190→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   191→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   192→                        println!();
   193→                        println!("{}", tack.text);
   194→                        if let Some(ref direction) = tack.direction {
   195→                            println!();
   196→                            println!("**Direction:** {}", direction);
   197→                        }
   198→                        println!();
   199→                    }
   200→                }
   201→            }
   202→        } else {
   203→            // List view: numbered paces
   204→            // If --remaining, output markdown format
   205→            if args.remaining {
   206→                let mut complete_count = 0;
   207→                let mut abandoned_count = 0;
   208→                let mut rough_count = 0;
   209→                let mut bridled_count = 0;
   210→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   211→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   212→
   213→                for coronet_key in &heat.order {
   214→                    if let Some(pace) = heat.paces.get(coronet_key) {
   215→                        if let Some(tack) = pace.tacks.first() {
   216→                            match tack.state {
   217→                                PaceState::Complete => complete_count += 1,
   218→                                PaceState::Abandoned => abandoned_count += 1,
   219→                                PaceState::Rough => {
   220→                                    rough_count += 1;
   221→                                    remaining_paces.push((coronet_key, pace));
   222→                                    if first_remaining_pace.is_none() {
   223→                                        first_remaining_pace = Some((coronet_key, pace));
   224→                                    }
   225→                                }
   226→                                PaceState::Bridled => {
   227→                                    bridled_count += 1;
   228→                                    remaining_paces.push((coronet_key, pace));
   229→                                    if first_remaining_pace.is_none() {
   230→                                        first_remaining_pace = Some((coronet_key, pace));
   231→                                    }
   232→                                }
   233→                            }
   234→                        }
   235→                    }
   236→                }
   237→
   238→                let status_str = match heat.status {
   239→                    HeatStatus::Racing => "racing",
   240→                    HeatStatus::Stabled => "stabled",
   241→                    HeatStatus::Retired => "retired",
   242→                };
   243→
   244→                let remaining_count = rough_count + bridled_count;
   245→
   246→                // Header line with heat info
   247→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   248→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   249→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   250→                println!();
   251→
   252→                // Table with remaining paces
   253→                if !remaining_paces.is_empty() {
   254→                    // Set up table with column definitions
   255→                    let mut table = jjrp_Table::jjrp_new(vec![
   256→                        jjrp_Column::new("No", jjrp_Align::Right),
   257→                        jjrp_Column::new("State", jjrp_Align::Left),
   258→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   259→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   260→                    ]);
   261→
   262→                    // Measure all rows to compute column widths
   263→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   264→                        if let Some(tack) = pace.tacks.first() {
   265→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   266→                            table.jjrp_measure(&[
   267→                                &(idx + 1).to_string(),
   268→                                state_str,
   269→                                &tack.silks,
   270→                                coronet_key,
   271→                            ]);
   272→                        }
   273→                    }
   274→
   275→                    // Print header and separator
   276→                    table.jjrp_print_header();
   277→                    table.jjrp_print_separator();
   278→
   279→                    // Print data rows
   280→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   281→                        if let Some(tack) = pace.tacks.first() {
   282→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   283→                            table.jjrp_print_row(&[
   284→                                &(idx + 1).to_string(),
   285→                                state_str,
   286→                                &tack.silks,
   287→                                coronet_key,
   288→                            ]);
   289→                        }
   290→                    }
   291→                    println!();
   292→                }
   293→
   294→                // Next up callout
   295→                if let Some((coronet_key, pace)) = first_remaining_pace {
   296→                    if let Some(tack) = pace.tacks.first() {
   297→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   298→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   299→                    }
   300→                }
   301→            } else {
   302→                // Column-justified list view (all paces)
   303→                // Set up table with column definitions
   304→                let mut table = jjrp_Table::jjrp_new(vec![
   305→                    jjrp_Column::new("No", jjrp_Align::Right),
   306→                    jjrp_Column::new("State", jjrp_Align::Left),
   307→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   308→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   309→                ]);
   310→
   311→                // Measure all rows to compute column widths
   312→                let mut num = 0;
   313→                for coronet_key in &heat.order {
   314→                    if let Some(pace) = heat.paces.get(coronet_key) {
   315→                        if let Some(tack) = pace.tacks.first() {
   316→                            num += 1;
   317→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   318→                            table.jjrp_measure(&[
   319→                                &num.to_string(),
   320→                                state_str,
   321→                                &tack.silks,
   322→                                coronet_key,
   323→                            ]);
   324→                        }
   325→                    }
   326→                }
   327→
   328→                // Print header and separator
   329→                table.jjrp_print_header();
   330→                table.jjrp_print_separator();
   331→
   332→                // Print data rows
   333→                let mut num = 0;
   334→                for coronet_key in &heat.order {
   335→                    if let Some(pace) = heat.paces.get(coronet_key) {
   336→                        if let Some(tack) = pace.tacks.first() {
   337→                            num += 1;
   338→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   339→                            table.jjrp_print_row(&[
   340→                                &num.to_string(),
   341→                                state_str,
   342→                                &tack.silks,
   343→                                coronet_key,
   344→                            ]);
   345→                        }
   346→                    }
   347→                }
   348→            }
   349→        }
   350→
   351→        // Always show file-touch bitmap and commit swim lanes after pace listing
   352→        zjjrpd_print_file_bitmap(&firemark, heat);
   353→        zjjrpd_print_commit_swimlanes(&firemark, heat);
   354→    } else {
   355→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   356→        return 1;
   357→    }
   358→
   359→    0
   360→}
