   362→/// Build and print the file-touch bitmap for a heat.
   363→///
   364→/// Uses shared query routines from jjrq_query to get file touches,
   365→/// then formats as a bitmap with columns per pace and rows per file,
   366→/// grouped by identical touch patterns.
   367→fn zjjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) {
   368→    let touches = match jjrq_file_touches_for_heat(firemark.jjrf_as_str()) {
   369→        Ok(t) => t,
   370→        Err(e) => {
   371→            eprintln!("jjx_parade: error getting file touches: {}", e);
   372→            return;
   373→        }
   374→    };
   375→
   376→    let has_heat_level = !touches.heat_files.is_empty();
   377→
   378→    // Build pace columns: only paces with commits, in heat order
   379→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
   380→    for coronet_key in &heat.order {
   381→        if !touches.coronets_with_commits.contains(coronet_key) {
   382→            continue;
   383→        }
   384→        if let Some(pace) = heat.paces.get(coronet_key) {
   385→            if let Some(tack) = pace.tacks.first() {
   386→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
   387→                if let Some(ch) = raw.chars().last() {
   388→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
   389→                }
   390→            }
   391→        }
   392→    }
   393→
   394→    // Map coronet_display -> column index
   395→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
   396→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
   397→        coronet_to_col.insert(coronet_display.clone(), idx);
   398→    }
   399→
   400→    let heat_col_idx = pace_columns.len();
   401→    let total_cols = if has_heat_level { heat_col_idx + 1 } else { heat_col_idx };
   402→
   403→    // Build file -> touch vector from the shared query result
   404→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
   405→
   406→    for (coronet, files) in &touches.pace_files {
   407→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
   408→            for filename in files {
   409→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   410→                if col_idx < row.len() {
   411→                    row[col_idx] = true;
   412→                }
   413→            }
   414→        }
   415→    }
   416→
   417→    if has_heat_level {
   418→        for filename in &touches.heat_files {
   419→            let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   420→            if heat_col_idx < row.len() {
   421→                row[heat_col_idx] = true;
   422→            }
   423→        }
   424→    }
   425→
   426→    if file_touches_map.is_empty() {
   427→        println!("File-touch bitmap: (no work file changes)");
   428→        return;
   429→    }
   430→
   431→    // Group files by identical touch pattern
   432→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
   433→    for (filename, pattern) in &file_touches_map {
   434→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
   435→    }
   436→
   437→    for files in pattern_groups.values_mut() {
   438→        files.sort();
   439→    }
   440→
   441→    // Print header
   442→    println!("File-touch bitmap (x = pace commit touched file):");
   443→    println!();
   444→
   445→    // Print vertical legend
   446→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
   447→        println!("  {} {} {}", i + 1, ch, silks);
   448→    }
   449→    if has_heat_level {
   450→        println!("  {} * heat-level", pace_columns.len() + 1);
   451→    }
   452→    println!();
   453→
   454→    // Print column header line (terminal chars aligned with bitmap positions)
   455→    let mut header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
   456→    if has_heat_level {
   457→        header_chars.push('*');
   458→    }
   459→    let header_line: String = header_chars.iter().collect();
   460→    println!("{}", header_line);
   461→
   462→    // Sort patterns: more touches first, then lexicographic
   463→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
   464→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
   465→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
   466→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
   467→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
   468→    });
   469→
   470→    for (pattern, files) in &sorted_patterns {
   471→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
   472→        println!("{} {}", bitmap, files.join(", "));
   473→    }
   474→}
