   486→/// Resolve the default heat (first racing heat) when no target is specified
   487→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   488→    for (heat_key, heat) in &gallops.heats {
   489→        if heat.status == HeatStatus::Racing {
